body:
transform does not reuse the object from the iteratee.

``` javascript
let _transform = _.transform.convert({ 
  'cap': false,
});
_transform( 
  (o, value, key) => _.set(key, value, o),
  { initial: "value" }, 
  { "my.new.values": 42 }
)
// => {initial:"value"}
```

That would be a bug, right?

This works though.
``` javascript
let _transform = _.transform.convert({ 
  'cap': false,
});

let _update = _.set.convert({immutable: false});

_transform( 
  (o, value, key) => _update(key, value, o),
  { initial: "value" }, 
  { "my.new.values": 42 }
)
// => 
{
  "initial": "value",
  "my": {
    "new": {
      "values": 42
    }
  }
}
```
